#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int P=1e9+7,inv2=(P+1)/2;

int T,k,f[65][2][2],na[65],nb[65],la,lb;
ll n,m;

int dfs(int i,int x,int y){
	if(~f[i][x][y])
		return f[i][x][y];
	int a=na[i],b=nb[i];
	if(!x && !y)
		return f[i][x][y]=1ll*k*(k+1)%P*inv2%P*dfs(i-1,0,0)%P;
	else if(!x && y)
		return f[i][x][y]=(1ll*b*(2*k-b+1)%P*inv2%P*dfs(i-1,0,0)+1ll*(k-b)*dfs(i-1,0,1))%P;
	else if(x && (!y || a<b))
		return f[i][x][y]=(1ll*a*(a+1)%P*inv2%P*dfs(i-1,0,0)+1ll*(a+1)*dfs(i-1,1,0))%P;
	else
		return f[i][x][y]=(1ll*b*(2*a-b+1)%P*inv2%P*dfs(i-1,0,0)+1ll*(a-b)*dfs(i-1,0,1)+1ll*b*dfs(i-1,1,0)+dfs(i-1,1,1))%P;
}

int main(){
    scanf("%d%d",&T,&k);
    while(T--){
        scanf("%lld%lld",&n,&m);
        m=min(m,n);
        memset(na,0,sizeof(na));
		memset(nb,0,sizeof(nb)) ;
        la=0,lb=0;
    	for(ll i=n;i;i/=k)
    		na[++la]=i%k;
    	for(ll i=m;i;i/=k)
    		nb[++lb]=i%k;
    	memset(f,-1,sizeof(f));
    	f[0][0][0]=f[0][0][1]=f[0][1][0]=f[0][1][1]=1;
    	n%=P,m%=P;
    	printf("%d\n",((1ll*(m+1)*(2*n-m+2)%P*inv2%P-dfs(la,1,1))%P+P)%P);
    }
    return 0;
}
